var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"연예계는 인기가 많아질수록 스케쥴도 늘어나요.","JPN":"芸能界というところは、人気が上がるほどスケジュールが厳しくなっていきます。","ENG":"In show biz, you'll get busier as you become more famous.","TWN":"隨著妳們在演藝界的人氣越來越高，行程安排也會越來越多。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"컨디션을 지키면서 팬들이 만족할 수 있는 스케쥴을 소화하는 건 확실히 힘들죠.","JPN":"万全のコンディションを保ちながら、ファンが満足するだけのスケジュールを\\n消化することは至難の業です。","ENG":"It's certainly very challenging to meet your fans' demands while trying to stay healthy.","TWN":"又要顧及身體，又要滿足粉絲，這確實是很累人的一件事。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"특히 체형유지에 항상 신경을 써야 하는 소녀 아이돌에겐 더 고된 일이에요.","JPN":"特に体型維持にいつも気を使わなければならない少女アイドルにとって、\\nそれはさらに過酷な課題です。","ENG":"It's extra challenging for girl groups who always have to watch their weight.","TWN":"特別是少女偶像還需要時刻注意維持身材，這就顯得尤其困難。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"조금만 무리해도 빈혈로 쓰러지거나, 몸살을 앓곤 하거든요.","JPN":"無理がたたって貧血で倒れたり、\\n寝込んでしまうことも多々ありますから。","ENG":"If you push yourself too hard, you could get anemic or suffer from fatigue.","TWN":"稍微勉強一點，可能就會貧血暈倒，積勞成疾。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"언제나 긍정적이며 활기차고 씩씩해야 할 아이돌이 팬들에게 힘든 모습을 보이는 건 곤란한 일이랍니다.","JPN":"いつも前向きで、元気で、凛々しくあるべきアイドルが、ファンに辛そうな姿を見せてしまっては困ります。","ENG":"This is especially tough when you're expected to always look perky and upbeat for your fans.","TWN":"然而偶像無論什麼時候，都要保持正面形象、充滿活力，絕對不能在粉絲們面前露出疲憊的樣子。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그래서 전 철인 그룹...... 아니, 카운터 아이돌 그룹을 꾸리기로 결심하게 된 거죠.","JPN":"だから私は、鉄人アスリートグループ……じゃなくて、\\nカウンターアイドルグループを作ろうと決めたんです。","ENG":"That's why I decided to form a band of superheroes... Uh, I mean, a girl group comprised of Counters.","TWN":"所以我決定要組一個鐵人團體……咳，我是說一個制裁者偶像團體。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아름답고, 강하고, 팬의 응원을 받으면 쓰러져도 다시 일어나는 그런 아이돌 말이에요.","JPN":"美しい上に強くて逞しい、ファンの応援さえあれば倒れてもまた立ち上がる、\\nそんなアイドルグループをです。","ENG":"No matter how tough the going gets, these beautiful stars are strong enough to get up again as their fans cheer on.","TWN":"美麗，強大。而且就算倒下，只要受到粉絲的加油，就會重新站起來的偶像。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"이전 기획사에선 다들 입을 모아 불가능할 거라고 했어요.","JPN":"これまで勤めていた事務所では、\\n誰もが不可能だと言っていました。","ENG":"Everyone at my previous agency said that it would be an impossible feat.","TWN":"之前的企劃公司口徑一致，全都覺得這不可能實現。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"물론 아이돌을 지망하는 소녀 카운터를 스카우트 한다는 건 저로서도 쉬운 일이 아니었죠.","JPN":"もちろんアイドル志望の少女カウンターをスカウトすることは、\\n私にとっても生易しいことではありませんでした。","ENG":"To be frank, it was difficult trying to find Counters who also wanted to become pop stars.","TWN":"當然，要找到想成為偶像的制裁者少女並不容易。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그래서 준비된 아이돌을 찾기보다, 가능성이 엿보이는 원석을 찾는 데에 집중했어요.","JPN":"なので、すでに準備ができているアイドルを探すより、見込みのある原石を\\n見つけることに専念してきました。","ENG":"So instead of finding someone who was ready to become a star, I focused on finding someone with potential.","TWN":"所以，比起尋找出道的偶像，我把精力都集中在擁有可能性的璞玉上。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"부족한 단점은 개성으로 승화시키고, 모난 성격은 훈련으로 교정하고, 열정이 없으면 목적의식을 심어주면서 말이죠.","JPN":"至らないところは個性に昇華させ、尖った性格は訓練で矯正し、\\n情熱がないなら目的意識を植えつけてあげたのです。","ENG":"We'd refine their character to stand out and train them to be more sociable. For the less motivated, we inspire them with clear objectives.","TWN":"將不足之處昇華為個性，性格缺陷由訓練來糾正，沒有熱情的話就樹立一個目標。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"비록 어려운 도전이었지만, 그 노력이 결실을 맺는 순간만큼은 정말 뿌듯하답니다.","JPN":"困難な挑戦ではありましたが、\\nその努力が実を結ぶ瞬間はまさに至福の時です。","ENG":"As challenging as it was, it's also very fulfilling to see it come to fruition.","TWN":"儘管這是個困難的課題，但努力開花結果的瞬間，卻是無比地令人驕傲。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그런 보람이 있기 때문에 매니지먼트를 자처할 수 있는 거겠죠.","JPN":"そんなやりがいを感じられるからこそ、こうして\\nマネジメント業を続けられているのだと思います。","ENG":"I guess that's what drives me to be their manager.","TWN":"正因為有這樣的價值，所以我才能以身為經紀人為傲吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"......어머, 시간이 벌써 그렇게 됐나요?","JPN":"……まあ、もうこんな時間なんですね？","ENG":"Oh, my. Look at the time!","TWN":"……哎呀，已經這個時間了嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"인터뷰는 여기에서 마치도록 할게요.","JPN":"インタビューはここまでにさせていただきますね。","ENG":"I'm afraid that's all the time I have for this interview.","TWN":"採訪就到此為止吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"하지만 저희 이야기는 끝나지 않았어요.","JPN":"ただし、私たちの物語はまだ終わっていません。","ENG":"But our story isn't over yet.","TWN":"但我們的故事還沒有結束喔。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"하트베리는 지금도 상승세, 현재진행형이거든요.","JPN":"ハートベリーは今も絶好調で、軌道に乗っていますので。","ENG":"HRT Berry is still attracting more fans. It's a work in progress.","TWN":"愛心莓果人氣的飆升，現在仍處於現在進行式。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"앞으로도 대중 여러분들의 열띤 응원과 관심! 부탁드릴게요.","JPN":"これもひとえに皆様のご声援のおかげです。これからもぜひ注目してくださいね！","ENG":"I look forward to everyone's keen interest and support. Thank you.","TWN":"希望大家今後也能熱情地為愛心莓果加油！謝謝大家。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};